import dataclasses, datetime
from typing import Optional

@dataclasses.dataclass
class KpiTile:
    label: str
    current_value: float
    previous_value: float
    unit: str = ""
    higher_is_better: bool = True

    @property
    def change_pct(self) -> float:
        if self.previous_value == 0:
            return 0.0
        return (self.current_value - self.previous_value) / self.previous_value

    @property
    def status(self) -> str:
        improved = (self.change_pct > 0) == self.higher_is_better
        magnitude = abs(self.change_pct)
        if magnitude < 0.02:
            return "neutral"
        return "good" if improved else ("warn" if magnitude < 0.10 else "bad")

    def format(self) -> str:
        direction = "▲" if self.change_pct >= 0 else "▼"
        return (
            f"{self.label}: {self.unit}{self.current_value:,.0f}  "
            f"{direction} {abs(self.change_pct):.0%} vs prior period  [{self.status}]"
        )


# Example tiles
tiles = [
