@dataclasses.dataclass
class MonthlySpendPoint:
    month: str          # e.g. "2025-06"
    actual_usd: Optional[float]    # None for future months
    forecast_usd: Optional[float]  # populated for future months
    budget_usd: float

    @property
    def is_actual(self) -> bool:
        return self.actual_usd is not None

    @property
    def value(self) -> float:
        return self.actual_usd if self.is_actual else (self.forecast_usd or 0.0)

    @property
    def vs_budget_pct(self) -> float:
        return self.value / self.budget_usd if self.budget_usd > 0 else 0.0


def build_trend_series(
    actuals: dict[str, float],
    forecast: dict[str, float],
    budget_usd: float,
) -> list[MonthlySpendPoint]:
    all_months = sorted(set(actuals) | set(forecast))
    return [
        MonthlySpendPoint(
            month=m,
            actual_usd=actuals.get(m),
            forecast_usd=forecast.get(m),
            budget_usd=budget_usd,
        )
        for m in all_months
    ]

@dataclasses.dataclass
class TeamSpendRow:
    team: str
    mtd_spend_usd: float
    prior_month_usd: float
    monthly_budget_usd: float
    total_spend_usd: float  # company-wide, for share calculation

    @property
    def share_pct(self) -> float:
        return self.mtd_spend_usd / self.total_spend_usd if self.total_spend_usd > 0 else 0.0

    @property
    def mom_change_pct(self) -> float:
        if self.prior_month_usd == 0:
            return 0.0
        return (self.mtd_spend_usd - self.prior_month_usd) / self.prior_month_usd

    @property
    def budget_pct(self) -> float:
        return self.mtd_spend_usd / self.monthly_budget_usd if self.monthly_budget_usd > 0 else 0.0

    @property
    def budget_status(self) -> str:
        p = self.budget_pct
        if p > 1.0:
            return "OVER"
        if p > 0.90:
            return "at risk"
        return "ok"

    def format_row(self) -> str:
        return (
            f"{self.team:<20} ${self.mtd_spend_usd:>9,.0f}  "
            f"{self.share_pct:>5.1%}  {self.mom_change_pct:>+6.1%}  {self.budget_status}"
        )

@dataclasses.dataclass
class ExecutiveAlert:
    alert_type: str   # "budget_overrun" | "spend_spike" | "commitment_lag" | "forecast_breach"
    team: str
    description: str
    severity: str     # "critical" | "warning"
    action_required: str

    def format(self) -> str:
        icon = "🔴" if self.severity == "critical" else "🟡"
        return f"{icon} [{self.alert_type}] {self.team}: {self.description} → {self.action_required}"


def generate_executive_alerts(
    teams: list[TeamSpendRow],
    commitment_utilisation_pct: float,
    forecast_vs_budget_pct: float,
) -> list[ExecutiveAlert]:
    alerts = []
    for t in teams:
        if t.budget_pct > 1.0:
            alerts.append(ExecutiveAlert(
                "budget_overrun", t.team,
                f"${t.mtd_spend_usd - t.monthly_budget_usd:,.0f} over monthly budget",
                "critical", "Review with team lead; apply throttle if unplanned"
            ))
        elif t.budget_pct > 0.90 and t.mom_change_pct > 0.20:
            alerts.append(ExecutiveAlert(
                "spend_spike", t.team,
                f"+{t.mom_change_pct:.0%} MoM growth — on track to breach budget",
                "warning", "Investigate growth driver before end of month"
            ))
    if commitment_utilisation_pct < 0.75:
        alerts.append(ExecutiveAlert(
            "commitment_lag", "FinOps",
            f"Commitment utilisation at {commitment_utilisation_pct:.0%} — true-up risk",
            "critical", "Activate workload migration plan; escalate to VP Engineering"
        ))
    if forecast_vs_budget_pct > 1.05:
        alerts.append(ExecutiveAlert(
            "forecast_breach", "Finance",
            f"Forecast exceeds budget by {(forecast_vs_budget_pct - 1):.0%}",
            "critical", "Request supplemental budget or implement spending controls"
        ))
    return alerts
